---战报数据
---@class LFightReportData
local LFightReportData = LxClass("LFightReportData",nil)
-----------------------------------------------------------------

---@type LFightRoundData
local LFightRoundData = LXImport(".LFightRoundData",nil)
LXImport(".LFightFormationData")
LXImport(".LFightDetailsData")
-----------------------------------------------------------------
function LFightReportData:LFightReportData()
	self.formationA = nil -- 阵型A
	self.formationB = nil -- 阵型B

	---@type LFightRoundData[]
	self._roundDataList = nil -- 回合数据

	self._totalRound = 0 --总回合数

	self._reportId = 0

	self._winner = 0 --胜利方 1 ，2
end

-----------------------------------------------------------------
function LFightReportData:InitReportData(tblJson,isPbData)
	self._reportId = tblJson.id
	self._winner = tblJson.winner
	self._combatType = tblJson.combatType

	local roundDataList = {}
	self._roundDataList = roundDataList
	local rounds = tblJson.rounds

    local lifeState = {}

	if isPbData then
		for k,v in ipairs(rounds) do
			local roundData = LFightRoundData:New()
			roundData:InitPbRoundData(v,lifeState)
			table.insert(roundDataList,roundData)
		end
	else
		for k,v in ipairs(rounds) do
			local roundData = LFightRoundData:New()
			roundData:InitJsonRoundData(v)
			table.insert(roundDataList,roundData)
		end
	end


	table.sort(roundDataList,function (rA,rB)
		return rA:GetRound() < rB:GetRound()
	end)

	self._totalRound = #roundDataList

	if isPbData then
		local formationData = LFightFormationData:New()
		formationData:CreateByPb(tblJson.formationA)
		formationData:SetServerId(tblJson.serverIdA)
		self.formationA = formationData
		formationData = LFightFormationData:New()
		formationData:CreateByPb(tblJson.formationB)
		formationData:SetServerId(tblJson.serverIdB)
		self.formationB = formationData
		self.details = LFightDetailsData:New()
		self.details:CreateByPb(tblJson.details)

		self.maxRound = tblJson.maxRound

		self.initShowJson = tblJson.initShowJson
	else
		self.formationA = tblJson.formationA
		self.formationB = tblJson.formationB
		self.details = tblJson.details
	end


    self.lifeState = lifeState

end

-----------------------------------------------------------------
function LFightReportData:GetReportId()
	return self._reportId
end

function LFightReportData:GetWinner()
	return self._winner
end

function LFightReportData:GetFormationA()
	return self.formationA
end

function LFightReportData:GetFormationB()
	return self.formationB
end

---@return LFightRoundData[]
function LFightReportData:GetRoundDataList()
	return self._roundDataList
end

function LFightReportData:GetTotalRound()
	return self._totalRound
end

function LFightReportData:GetCombatDetails()
	return self.details
end

function LFightReportData:GetCombatUnitBySide(side)
	if side == LFightConst.SIDE_TEAM_A then
		return self._combatUnitListA
	else
		return self._combatUnitListB
	end
end

function LFightReportData:CreateNoRound(data)
	self.id = data.id
	local isPb = false
	local s,e = string.find(self.id,"pb")
	if s and e then
		isPb = true
	end

	if isPb then
		self.formationA = LFightFormationData:New()
		self.formationA:CreateByPb(data.formationA)
		self.formationA:SetServerId(data.serverIdA)
		self.formationB = LFightFormationData:New()
		self.formationB:CreateByPb(data.formationB)
		self.formationB:SetServerId(data.serverIdB)
		self.details = LFightDetailsData:New()
		self.details:CreateByPb(data.details)
		self.winner = data.winner
		self.combatType = data.combatType
	else
		self.formationA = data.formationA
		self.formationB = data.formationB
		self.details = data.details
		self.winner = data.winner
		self.combatType = data.combatType
	end
end

function LFightReportData:GetLifeState()
    return self.lifeState
end

function LFightReportData:GetMaxRound()
	return self.maxRound
end

function LFightReportData:GetMonsterAttrId(side)
	if side == LFightConst.SIDE_TEAM_A then
		return self.formationA.monsterFormationRefId
	else
		return self.formationB.monsterFormationRefId
	end
end

function LFightReportData:GetCombatType()
	return self._combatType
end

function LFightReportData:GetFormationName(isLeft)
	if isLeft then
		return self.formationA.formationName
	else
		return self.formationB.formationName
	end

end

function LFightReportData:GetHeroGridMap()
	return self.formationA,self.formationB
end

function LFightReportData:GetShowInfo()
	return self.initShowJson
end

-----------------------------------------------------------------
return LFightReportData
